@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent {

}
<h1>📈 App gestión de Gastos e ingresos.</h1>

<section id="enlaces">
    <a routerLink="/new"><article>Nuevo registro</article></a>
    <a routerLink="/registros"><article>Lista registros</article></a>
</section>
